const t={boardTopology:{intro:{t:0,b:{t:2,i:[{t:3}],s:"查看打印机的控制板如何连接：主机（SBC）以及与之通信的每个 MCU，包含每种连接类型，并尽力推测板卡 / 芯片型号 —— 实时读取自配置。"}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"帮助"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"关于板卡拓扑"}},close:{t:0,b:{t:2,i:[{t:3}],s:"关闭"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"如何阅读"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"主机（你的 SBC，例如 Raspberry Pi 或 CB1）位于顶部。"}},{t:0,b:{t:2,i:[{t:3}],s:"每张 MCU 卡片显示其连接方式（USB / CAN bus / UART）及其芯片。"}},{t:0,b:{t:2,i:[{t:3}],s:"当连接标识符与已知板卡匹配时，会显示板卡推测结果。"}}],topics:{mcus:{title:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},body:{t:0,b:{t:2,i:[{t:3}],s:"MCU 是一块微控制器板卡，用于驱动电机、加热器和传感器。一台打印机至少有一个（主板）；许多还会加装工具头板卡，有时还有调平探头板或 LED 板。本面板列出 Klipper 拥有的每个 `[mcu]` 节。"}}},connections:{title:{t:0,b:{t:2,i:[{t:3}],s:"连接类型"}},body:{t:0,b:{t:2,i:[{t:3}],s:"USB —— 通过 USB 的串口连接（常见的主板连接方式）。CAN bus —— 一条共享的双线总线，常用于工具头板卡。UART —— 通过 GPIO 的直接串口连接。连接类型根据每个 MCU 的 `serial` / `canbus_uuid` 设置推断得出。"}}},detection:{title:{t:0,b:{t:2,i:[{t:3}],s:"检测原理"}},body:{t:0,b:{t:2,i:[{t:3}],s:"芯片和板卡通过将连接标识符（serial 路径或 CAN UUID）与模式表进行匹配来推测。板卡推测会显示匹配置信度；当没有任何匹配时，芯片/板卡显示为“未知”—— 但连接本身仍会显示。"}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"术语表"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{mcu:{term:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},def:{t:0,b:{t:2,i:[{t:3}],s:"微控制器单元 —— 运行 Klipper 固件的控制板卡（主板、工具头等）。"}}},canbus:{term:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},def:{t:0,b:{t:2,i:[{t:3}],s:"一条通过唯一 UUID 连接各板卡的双线共享总线 —— 在工具头布线中广受欢迎。"}}},host:{term:{t:0,b:{t:2,i:[{t:3}],s:"主机 / SBC"}},def:{t:0,b:{t:2,i:[{t:3}],s:"运行 Klipper 并与各 MCU 通信的单板计算机（Pi、CB1……）。"}}}}},host:{label:{t:0,b:{t:2,i:[{t:3}],s:"主机"}},role:{t:0,b:{t:2,i:[{t:3}],s:"单板计算机 —— 运行 Klipper"}}},mcu:{chip:{t:0,b:{t:2,i:[{t:3}],s:"芯片"}},board:{t:0,b:{t:2,i:[{t:3}],s:"板卡"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"未知"}},identifier:{t:0,b:{t:2,i:[{t:3}],s:"标识符"}},confidence:{t:0,b:{t:2,i:[{t:4,k:"pct"},{t:3,v:"% 匹配"}]}},viewBoard:{t:0,b:{t:2,i:[{t:3}],s:"查看主板详情"}},hideBoard:{t:0,b:{t:2,i:[{t:3}],s:"隐藏详情"}}},conn:{canbus:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},usb:{t:0,b:{t:2,i:[{t:3}],s:"USB"}},uart:{t:0,b:{t:2,i:[{t:3}],s:"UART"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"未知"}},via:{t:0,b:{t:2,i:[{t:3,v:"通过 "},{t:4,k:"type"}]}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" 个 MCU"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"正在读取拓扑……"}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"无法连接到打印机。"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"在配置中未找到 MCU。"}},retry:{t:0,b:{t:2,i:[{t:3}],s:"重试"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"刷新"}}},board:{suggested:{t:0,b:{t:2,i:[{t:3}],s:"推测匹配"}},ports:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" 个接口"}]}},specsTitle:{t:0,b:{t:2,i:[{t:3}],s:"规格"}},portsTitle:{t:0,b:{t:2,i:[{t:3}],s:"接口"}},none:{t:0,b:{t:2,i:[{t:3}],s:"暂无该主板的目录详情。"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"正在加载主板…"}},links:{title:{t:0,b:{t:2,i:[{t:3}],s:"链接"}},product:{t:0,b:{t:2,i:[{t:3}],s:"产品"}},repo:{t:0,b:{t:2,i:[{t:3}],s:"仓库"}},wiki:{t:0,b:{t:2,i:[{t:3}],s:"Wiki"}},pinout:{t:0,b:{t:2,i:[{t:3}],s:"引脚图"}},schematic:{t:0,b:{t:2,i:[{t:3}],s:"原理图"}},datasheet:{t:0,b:{t:2,i:[{t:3}],s:"数据手册"}},image:{t:0,b:{t:2,i:[{t:3}],s:"图片"}}}}}};export{t as default};
